SELECT DISTINCT lyr.mgr_seq, schem_nm, lyr.tbl_id, lyr_nm, lyr_typ, grp_mgr_seq, use_yn, geo_offset_x, geo_offset_y, lyr.mk_user, lyr.mk_dat, lyr_zidx, thm_use_yn, visible_yn, heat_yn, min_resolution, max_resolution



 	,platform_tab_auth, auth.mod_yn


FROM xeus.gis_lyr_list lyr

LEFT JOIN xeus.gis_lyr_grp grp ON grp.mgr_seq =lyr.grp_mgr_seq

LEFT JOIN xeus.mt_auth_lyr auth ON lyr.tbl_id=auth.tbl_id

LEFT JOIN xeus.mt_usr_desc usr ON usr.auth_grp_no = auth.auth_grp_no



		AND (

				(usr.user_id = #{userId} AND  grp.mgr_seq != 3 AND grp.mgr_seq != 6 AND auth.platform_tab_auth LIKE '%'||#{tabName}||'%')
				OR

				(grp.mgr_seq = 3 AND lyr.mk_user=#{userId})
			)



		AND (

				(usr.user_id = #{userId} AND  grp.mgr_seq != 3 AND grp.mgr_seq != 6)
				OR

				(grp.mgr_seq = 3 AND lyr.mk_user=#{userId})
			)



		AND mgr_seq = #{mgrSeq}::numeric



		AND schem_nm = #{schemNm}



		AND tbl_id = #{tblId}



		AND lyr_nm = #{lyrNm}



		AND lyr_typ = #{lyrTyp}



		AND grp_mgr_seq = #{grpMgrSeq}::numeric



		AND grp.grp_nm = #{grpNm}



		AND use_yn = #{useYn}::boolean



		AND geo_offset_x = #{geoOffsetX}::numeric



		AND geo_offset_y = #{geoOffsetY}::numeric



		AND lyr.mk_user = #{mkUser}



		AND lyr.mk_dat = #{mkDat}



		AND lyr_zidx = #{lyrZidx}::numeric



		AND thm_use_yn = #{thmUseYn}::boolean



		AND visible_yn = #{visibleYn}::boolean



		AND heat_yn = #{heatYn}::boolean



		AND min_resolution = #{minResolution}



		AND max_resolution = #{maxResolution}






		${sortCol} ${sortTyp}


		lyr_zidx asc




	LIMIT ${limit} OFFSET ${offset}

