mapper.insert:
INSERT INTO xeus.gis_lyr_list(
	schem_nm, tbl_id, lyr_nm, lyr_typ grp_mgr_seq, use_yn, geo_offset_x, geo_offset_y, mk_user, mk_dat,

	lyr_zidx,

	thm_use_yn, visible_yn, heat_yn, min_resolution, max_resolution
) VALUES (
	#{schemNm}, #{tblId}, #{lyrNm}, #{lyrTyp}, #{grpMgrSeq}::numeric, #{useYn}::boolean, #{geoOffsetX}::numeric, #{geoOffsetY}::numeric, #{mkUser}, #{mkDat},

	(select coalesce(max(lyr_zidx)+1, 1) from xeus.gis_lyr_list where grp_mgr_seq = #{grpMgrSeq}::numeric),

	#{thmUseYn}::boolean, #{visibleYn}::boolean, #{heatYn}::boolean, #{minResolution}, #{maxResolution}
);

